mapper.update:
UPDATE 
	FACILITY_MANAGE 
SET			
	FACILITY_NAME 		= #{facility_name}
	, FACILITY_DESC		= #{facility_desc}
	, START_TIME		= #{start_time}
	, END_TIME			= #{end_time}
	, LIMIT_COUNT		= #{limit_count}
	, APPLY_START_DATE	= #{apply_start_date}
	, APPLY_END_DATE	= #{apply_end_date}
	, APPLY_START_TIME	= #{apply_start_time}
	, APPLY_END_TIME	= #{apply_end_time}
	, USE_YN 			= #{use_yn}
	, MOD_DATE 			= SYSDATE
	, MOD_ID 			= #{mod_id}
	, BLACKBOARD_USE_YN = #{blackboard_use_yn}
WHERE
	HOMEPAGE_ID = #{homepage_id} AND FACILITY_IDX = #{facility_idx}

mapper.select:
SELECT HOMEPAGE_ID, FACILITY_IDX, FACILITY_NAME, FACILITY_DESC, USE_DATE, START_TIME, END_TIME, LIMIT_COUNT, APPLY_START_DATE, APPLY_END_DATE, APPLY_START_TIME, APPLY_END_TIME, USE_YN, DELETE_YN, ADD_DATE, ADD_ID, MOD_DATE, MOD_ID, BLACKBOARD_USE_YN, (SELECT COUNT(*) FROM FACILITY_REQ WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND FACILITY_IDX = a.FACILITY_IDX AND DELETE_YN = 'N') AS APPLY_COUNT FROM FACILITY_MANAGE a WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND substr(USE_DATE,0,7) in
EXTRACT(YEAR from sysdate) || '-' || #{i}
ORDER BY USE_DATE
